dax_calendar_patterns.minimal_calendar:
// Minimal: just the Date column
DateTable =
CALENDAR(DATE(2023,1,1), DATE(2026,12,31))

marking_as_date_table.validation_dax:
// Run these in a blank table measure to diagnose mark-as-date-table failures:
// Check for duplicates:
DateDuplicates = COUNTROWS('DateTable') - DISTINCTCOUNT('DateTable'[Date])
// Should be 0. If > 0, dates are not unique.

// Check for blanks:
DateBlanks = CALCULATE(COUNTROWS('DateTable'), ISBLANK('DateTable'[Date]))
// Should be 0.

// Check range covers full years:
DateRangeStart = MIN('DateTable'[Date])  -- should be Jan 1
DateRangeEnd   = MAX('DateTable'[Date])  -- should be Dec 31

snapshot_data_join_strategy.alternative_yearmonth_key:
If snapshot dates are not normalised to the 1st, add a YearMonth integer key (YYYYMM) to both tables and create the relationship on that key instead of Date. This is more robust.

// In DateTable (DAX calculated column or ADDCOLUMNS):
"YearMonthKey", YEAR([Date]) * 100 + MONTH([Date])   -- 202601

// In FactTable (Power Query M step):
AddYearMonthKey = Table.AddColumn(Source, "YearMonthKey",
    each Date.Year([SnapshotDate]) * 100 + Date.Month([SnapshotDate]),
    Int64.Type)

// Then relationship: DateTable[YearMonthKey] (1) -> FactTable[YearMonthKey] (*)
// This joins on YYYYMM integers — no ambiguity about day.

multiple_fact_tables.quarterly_key_example:
// Add QuarterKey to DateTable:
"QuarterKey", YEAR([Date]) * 10 + QUARTER([Date])   -- 20261, 20262 …

// In quarterly fact table (Power Query M):
AddQuarterKey = Table.AddColumn(Source, "QuarterKey",
    each Date.Year([QuarterStartDate]) * 10 + Date.QuarterOfYear([QuarterStartDate]),
    Int64.Type)

snapshot_join.example:
Fact row: {SnapshotDate: 2026-03-01, Metric: 'Sev5 Count', Value: 142}
Date table row: {Date: 2026-03-01, Month: 3, QuarterLabel: 'Q1 2026'}
Join: FactTable[SnapshotDate] = DateTable[Date] — works directly.

range_join.workaround_pattern:
// For range-based reporting (e.g. how many vulns were OPEN in each month):
// Do NOT try to create a range relationship.
// Instead: build a bridge table in Power Query that explodes each open period
// into one row per month it covers:

// Power Query M: expand date ranges to month-rows
ExpandRanges = Table.TransformRows(FactTable, (row) =>
    let
        StartMonth = Date.StartOfMonth(row[OpenDate]),
        EndMonth   = Date.StartOfMonth(row[CloseDate] ?? DateTime.Date(DateTime.LocalNow())),
        MonthCount = Duration.Days(EndMonth - StartMonth) / 30 + 1,
        Months     = List.Generate(
            () => StartMonth,
            each _ <= EndMonth,
            each Date.AddMonths(_, 1)
        )
    in
        List.Transform(Months, (m) => Record.AddField(row, "MonthDate", m))
)
